var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그래서, 날아간 학우들을 찾는 일에 협조해 달라...... 그런 말씀이십니까?","JPN":"で、飛ばされた学友たちを探すのを手伝ってほしい……ということですか？","ENG":"So, you want me to help you find some students who were blown away. Is that correct?","TWN":"所以，妳們希望我幫忙一起尋找炸飛的失蹤同學……是這意思嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"응, 그렇게 됐어.","JPN":"うん、そういうことよ。","ENG":"Yes.","TWN":"嗯，就是這樣。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"위상 방벽이 망가진 곳을 통해서 침식체들이 계속 들어오고 있는 모양이더라고.","JPN":"位相防壁が壊れた所から、侵食体が次々と入ってきてるみたいなの。","ENG":"Corrupted Objects are constantly sneaking into the city through the holes in the phase barrier.","TWN":"據說，侵蝕體正通過相位屏障被破壞的地方不斷湧進來。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아까 등굣길에 봤는데, 피난이 끝난 시가지 쪽은 침식체에게 이미 점령당했나 봐.","JPN":"さっき登校しながら見たんだけど、避難が終わった市街地のほうは侵食体に占領されたみたい。","ENG":"I saw on my way to school today that the streets that had been vacated are already infested with them.","TWN":"就像剛才在上學的路上看到的一樣，疏散完畢的街道很有可能已經被侵蝕體佔領了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"이곳 저곳 찾아 다니려면 한 명이라도 더 많은 편이 좋잖아?","JPN":"あちこち探さないといけないから、一人でも多いほうがいいでしょう？","ENG":"Since we have to search everywhere, we need all the help we can get.","TWN":"我們就到處找找看，如果能多一個人來找不是很好嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"미안하지만 부탁 좀 할게, 사서님?","JPN":"申し訳ないけどお願いね、司書さん？","ENG":"Please, Librarian. Help us, please?","TWN":"有件事我感到很抱歉，但我必須要拜託您。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"공적인 업무를 수행할 때는 학생회 서기라는 명칭을 사용해 주시기 바랍니다.","JPN":"公的業務を行う時は、生徒会書記という名称を使っていただけますか？","ENG":"Please address me as the Student Council Clerk when we're discussing official matters.","TWN":"我希望您在執行公務時，能以學生會書記作為稱呼。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그보다 얘기를 듣고도 믿기 어렵군요. 선도부장, 당신이 이런 사고를 일으킬 줄이야.","JPN":"それより信じられない話ですね。\\n風紀委員長、まさかあなたがこんな事故を起こすとは。","ENG":"By the way, this is hard to believe. Student Guide Leader, you never cause trouble.","TWN":"不然聽到這些事情的人大概都會感到不可置信，沒想到我們的先鋒部隊長竟然會引起這樣的意外。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"면목없다...... 감정에 휩쓸려 출력을 너무 올렸어......","JPN":"すまない……感情に流されて出力を上げ過ぎてしまった……","ENG":"I'm ashamed... I let my emotions get the worst of me...","TWN":"真是慚愧…就因為我一時衝動，不小心提高了輸出功率……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"흠, 그 냉철하던 선도부장도 유진 양처럼 실수를 할 때가 있다니 의외군요.","JPN":"ふむ、あの冷徹な風紀委員長もシロコさんのようなミスをすることがあるなんて意外です。","ENG":"Hmm, even you can be as troublesome as Eujin sometimes.","TWN":"嗯，沒想到一向冷靜的先鋒部隊長也有像劉珍一樣闖禍的時候啊，真令人意外。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"야! 왜 하필 거기서 내 이름이 나오는 건데?","JPN":"おい！　なんでそこで俺の名前が出てくるんだ？","ENG":"Hey, why did you say my name?","TWN":"喂！為什麼我的名字會在這時候出現啊？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그야 원래부터 사사건건 문제를 일으키는 건 유진 양 전담이었지 않습니까?","JPN":"だって、いつも何か問題を引き起こすのはシロコさんだったじゃないですか。","ENG":"Because you're always a troublemaker.","TWN":"因為妳就是專業製造問題機小劉珍啊~"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭐야, 짜샤?!","JPN":"何だと？　こら！","ENG":"What? You schmuck!","TWN":"妳說什麼，小鬼！！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그런 끓는 점이 낮은 성격도 문제입니다.","JPN":"そのすぐにカッとなる性格も問題ですよ。","ENG":"You're quick to anger, too.","TWN":"然後燃點低的性格也是個問題。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"도서관에는 명상에 대한 서적도 비치되어 있습니다.","JPN":"図書館には瞑想に関する書籍も備えられています。","ENG":"We have good meditation books at the Library.","TWN":"圖書館裡有些關於冥想的書籍..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"심리학적인 부분에는 조예도 관심도 없지만, 유진 양이 그 다혈질을 치료하고 싶다면 몇 권 추천해 드리죠.","JPN":"心理学的な分野は造詣も興味もありませんが、\\nシロコさんがその血の気の多い性格を直したいなら何冊かおすすめしましょう。","ENG":"I'm not interested or knowledgeable in psychology, but I can recommend a few good books if you're interested in anger management.","TWN":"雖然我對心理學方面的書沒什麼興趣，不過要是小劉珍想治療她衝動的毛病，我倒是可以推薦幾本。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"이, 이 자식이 진짜......","JPN":"こ、こいつ……タダじゃおかねぇ……","ENG":"Y-you, you arrogant...","TWN":"這、這傢夥真是..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"하하. 그만해, 유진아. 말싸움할 때마다 본전도 못 찾았잖아.","JPN":"あはは。もうやめて、シロコ。口げんかするために来たんじゃないでしょう。","ENG":"Hah hah. Don't, Eujin. You never win when you argue with him.","TWN":"哈哈，算了吧，劉珍。妳不是每次吵架都不會贏嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"네. 저도 불필요한 언쟁은 사양하겠습니다.","JPN":"はい。僕も不要な言い争いは遠慮したいです。","ENG":"No, and I don't want unnecessary arguments, either.","TWN":"是啊，我也對這種無義意的爭吵敬謝不敏。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그보다 새삼 놀랍군요. 유진 양의 사고 능력이 언쟁을 벌일 만큼 고등하다니.","JPN":"それにしても驚きましたね。シロコさんの思考能力が言い争いをするほど高かったなんて。","ENG":"By the way, I'm surprised that you think Eujin is intelligent enough to even try to argue with me.","TWN":"但比起這個，更讓我驚訝的是小劉珍的思考能力跟她的吵架能力一樣厲害呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"크아악! 너 지금 나한테 시비 터냐!","JPN":"おいっ！　お前、俺にケンカ売ってるだろ！","ENG":"Gwarrggh! Do you want a piece of me? Is that it?","TWN":"喂！妳現在是不是又在跟我找碴？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그리고 아이리 양과 시엔 양을 찾는 일은 간단합니다.","JPN":"あと、アイリさんとシエンさんを探すことは簡単です。","ENG":"And it's easy to find Irie and Xien.","TWN":"還有，要找艾莉和西恩小姐其實很簡單。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"정말인가?","JPN":"本当か？","ENG":"Is it?","TWN":"真的嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"역시 학생회의 참모장이네. 무슨 비책이 있는 거야?","JPN":"さすが生徒会の参謀長ね。何か秘策でもあるわけ？","ENG":"There's a reason you're the chief of staff of the Student Council. Alright, what strategy are you thinking?","TWN":"不愧是學生會參謀長啊，妳有什麼計策?"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"비책이 아니라, 단순한 계산입니다.","JPN":"秘策ではなく、単純な計算です。","ENG":"It's not a strategy; it's a simple calculation.","TWN":"不是什麼“計策”，就只是個單純的計算而已。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"선도부장이 사용하는 버고 소드의 최대 출력과, 두 사람의 신장에 따른 평균 체중, 그리고 제가 도서관에서 목격한 포물선의 각도로 추정해 봤을 때......","JPN":"風紀委員長が使うヴァルゴソードの最大出力と二人の身長から算出した平均体重、\\n僕が図書館で目撃した放物線の角度から推定すると……","ENG":"Judging by the maximum output of the Student Guide Leader's Virgo Sword, the average weight of those two based on their heights, and the angles of their trajectories that I saw from the Library...","TWN":"部隊長使用布林加夫之劍的最大功率加上兩人身高體重的平均值，以及我在圖書館看到的拋物線的角度來推斷……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"70초 후 살려 달라고 아카데미로 돌아오게 되어 있습니다.","JPN":"70秒後には、助けてくれと叫びながらアカデミーに帰ってくるでしょう。","ENG":"they'll come running for help exactly in 70 seconds.","TWN":"70秒後，她們會活著回到學院裡。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"흥. 그게 말이 되냐? 그냥 찍어 놓고 그럴싸하게 포장하는 거 아냐?","JPN":"ふん、そんなのあり得るかよ。当てずっぽうなのをそれらしく言っただけじゃないか？","ENG":"Hmpf, you're kidding. You just took an educated guess, didn't you?","TWN":"哼，有這種事？妳只是隨便說說而已嘛....."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"제 계산이 틀렸는지 맞는지는......","JPN":"僕の計算が間違っているかどうか……","ENG":"You'll see whether or not my calculation is correct","TWN":"我到底是算對還是算錯……"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"정확히 60초 후에 공개됩니다.","JPN":"正解は60秒後！","ENG":"in exactly 60 seconds.","TWN":"正確答案會在60秒後揭曉。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"뭔 그런 철 지난 멘트를......","JPN":"何だその昔の司会者みたいなコメントは……","ENG":"You're not a rocket scientist—","TWN":"這什麼過時的用語..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"IRIE_CIVIL_SPRING_NULL","text":{"KOREA":"으아앙~ 따라잡히겠어~ 기운 내, 붕붕아~","JPN":"うわ～ん。追いつかれちゃうよ～元気出して、ブンブンちゃ～ん。","ENG":"Waaah! They're going to catch us! Bear up, Vroom!","TWN":"喔哦哦~我會追上你的！！打起精神來，蓬蓬！"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"잠깐! 나는 태워 줘야 할 거 아냐!","JPN":"待て！　私を乗せないのはダメだろ！","ENG":"Wait! Why are you leaving me behind?","TWN":"等等！妳不是要載我嗎!"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L49_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아가씨! 도보로 등교하시는 서민적인 모습, 아름답습니다!</color>","JPN":"<color=#ffd34c>お嬢様！　徒歩で登校される庶民的なお姿、お美しいです！</color>","ENG":"<color=#ffd34c>My lady! You're walking to school, just like everyone else. How beautiful!</color>","TWN":"<color=#ffd34c>嘖嘖，小姐徒步上學的平民形象真是美極了！</color>"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"뭣......!","JPN":"なっ……！","ENG":"What?","TWN":"什....!"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"훗, 그랬나. 내가 동경하던 서민의 생활상을, 나도 모르게 몸에 익히고 있었다니......","JPN":"ふっ、そうか。私が憧れていた庶民の生活像を、知らないうちに身につけていたとは……","ENG":"Hah, am I? So, I've been living the life of a commoner like I've always wanted. I just didn't know it until now.","TWN":"哼，就是啊，我竟然不知不覺間我學會了我嚮往的平民生活……"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"린 시엔, 무서운 아이!","JPN":"リン・シエン、なんて恐ろしい子だ！","ENG":"Lin Xien, you're so amazing!","TWN":"林·西恩，可怕的孩子!"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"으갸악! 물지 마! 아프다구!","JPN":"うあっ！　噛むな！　痛いだろ！","ENG":"WAH! Stop biting! It hurts!","TWN":"哎喲！別咬我！都說很痛了！"},"stage":{"bg":"STREET_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어...... 진짜 오네......","JPN":"おお……本当に来たな……","ENG":"Err... They're really coming...","TWN":"欸...真的來了啊..."},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"시간에 딱 맞춰 왔군요.","JPN":"時間ぴったりに来ましたね。","ENG":"They're right on time.","TWN":"時間剛剛好呢。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"뒤에 쫓아오는 건 3종 침식체인가! 두 사람만으로는 버겁겠군!","JPN":"後に追ってくるのは第3種侵食体か！　二人だけじゃ手に負えないだろう！","ENG":"And they have a Category 3 C.O. hot on their heels. There's no way they can handle it on their own.","TWN":"在後面追妳們的是第3類侵蝕體嗎？就只有妳們是應付不來的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아하하...... 추억 삼아 남길 영상이었는데 결국 침식체는 빠지질 않네.","JPN":"あはは……思い出に残そうとした映像なのに、侵食体まで映り込んじゃったね。","ENG":"Ah hah hah... I wanted this video to be special, but we can never get away from C.O.'s, can we?","TWN":"啊哈哈哈是啊...本來想要拍個紀念影片的，結果又殺出了一個侵蝕體。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"지금 같은 시기에는 무리겠지.","JPN":"今は仕方ないさ。","ENG":"Not in times like this, no.","TWN":"在這種非常時期是沒辦法的吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"서기, 반장. 그리고 유진. 이대로 두면 아카데미 건물까지 파괴될지 모른다.","JPN":"書記、委員長。それからシロコ。このままだとアカデミーの建物まで破壊されかねない。","ENG":"Clerk. Class President. And Eujin. If we leave that thing alone, it could destroy the Academy buildings.","TWN":"書記、班長、以及劉珍啊，如果再繼續這樣下去，說不定連我們學校的建築物都會遭到破壞的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"그런 건 다들 원하지 않겠지?","JPN":"そんなことは望んでないだろう？","ENG":"You don't want that, do you?","TWN":"大家都不願意看到這種情況吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"당연하지. 떠나는 날에 폭삭 망해 버리면 안 되잖아.","JPN":"当たり前だ。最後の日に学校が壊されるなんて、たまったもんじゃない。","ENG":"Of course not. I don't want to destroy the school on my last day.","TWN":"那當然，學校總不能在我們離開的這天毀掉吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"아카데미는 교육의 요람. 침식체 따위가 날뛰게 두지 않습니다.","JPN":"アカデミーは教育の揺りかご。侵食体なんかに暴れさせるわけにはいきません。","ENG":"The Academy is the cradle of education. I will not let any C.O. ruin it.","TWN":"學校是教育的搖籃，不容許侵蝕體這等邪惡勢力在此倡狂。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"다들 같은 생각인 것 같아.","JPN":"みんないい覚悟ね。","ENG":"Everyone's on the same page.","TWN":"大家的想法應該都是一樣的。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"촬영은 내게 맡겨. 멋지게 편집해서 보여 줄게.","JPN":"撮影は私に任せて。きちんと編集してみせてあげる。","ENG":"Leave the filming to me. I'll edit and make this scene look awesome, too.","TWN":"那攝影就交給我吧，我會把影片剪得很漂亮的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"좋다, 제군들! 제 3종 침식체를 요격하고 학우들을 구출한다!","JPN":"よし、諸君！　第3種侵食体を迎撃して、学友を救出するぞ！","ENG":"Alright, everyone! Let's get rid of the Category 3 C.O. and save our fellow students.","TWN":"是可以啦，那麼諸位！讓我們去迎擊第3侵蝕體，救出同學吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_SPRING_NULL","text":{"KOREA":"가자!","JPN":"行こう！","ENG":"Let's go!","TWN":"上啊！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_SPRING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};